/*! msal-shim v2.0 — PKCE Authorization Code Flow
 *  Implementação própria para GitHub Pages + Microsoft Entra ID
 *  Compatible com: PublicClientApplication API (MSAL v2/v3)
 */
(function(g){'use strict';

function b64url(buf){
  return btoa(String.fromCharCode.apply(null,new Uint8Array(buf)))
    .replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}
async function genPkce(){
  var v=b64url(crypto.getRandomValues(new Uint8Array(32)));
  var d=await crypto.subtle.digest('SHA-256',new TextEncoder().encode(v));
  return{verifier:v,challenge:b64url(d)};
}
function genState(){return b64url(crypto.getRandomValues(new Uint8Array(16)));}
function parseJwt(t){
  try{return JSON.parse(atob(t.split('.')[1].replace(/-/g,'+').replace(/_/g,'/')));}
  catch(e){return{};}
}

function PCA(cfg){
  this._cfg=cfg;
  this._store=cfg.cache&&cfg.cache.cacheLocation==='localStorage'?localStorage:sessionStorage;
  this._key='__msal_shim_'+cfg.auth.clientId;
  this._initialized=false;
}

PCA.prototype.initialize=function(){
  this._initialized=true;
  return Promise.resolve();
};

PCA.prototype._save=function(d){
  try{this._store.setItem(this._key,JSON.stringify(d));}catch(e){}
};
PCA.prototype._load=function(){
  try{return JSON.parse(this._store.getItem(this._key)||'null');}catch(e){return null;}
};

PCA.prototype.getAllAccounts=function(){
  var d=this._load();
  return(d&&d.account)?[d.account]:[];
};

PCA.prototype.handleRedirectPromise=function(){
  return Promise.resolve(null);
};

PCA.prototype.acquireTokenSilent=function(req){
  var self=this;
  return new Promise(async function(res,rej){
    var d=self._load();
    if(!d||!d.access_token){rej(new Error('no_account'));return;}
    // Token válido com 5min de margem
    if(d.expires_at&&Date.now()<d.expires_at-300000){
      res({accessToken:d.access_token,account:d.account});return;
    }
    // Renovar via refresh_token
    if(!d.refresh_token){rej(new Error('no_refresh_token'));return;}
    try{
      var tid=self._cfg.auth.authority.replace(/.*\//,'');
      var body=new URLSearchParams({
        client_id:self._cfg.auth.clientId,
        grant_type:'refresh_token',
        refresh_token:d.refresh_token,
        scope:(req.scopes||[]).join(' ')+' offline_access'
      });
      var r=await fetch('https://login.microsoftonline.com/'+tid+'/oauth2/v2.0/token',
        {method:'POST',body:body,headers:{'Content-Type':'application/x-www-form-urlencoded'}});
      var t=await r.json();
      if(t.error){rej(new Error(t.error_description||t.error));return;}
      d.access_token=t.access_token;
      d.expires_at=Date.now()+t.expires_in*1000;
      if(t.refresh_token)d.refresh_token=t.refresh_token;
      self._save(d);
      res({accessToken:t.access_token,account:d.account});
    }catch(e){rej(e);}
  });
};

PCA.prototype.loginPopup=function(req){
  var self=this;
  return new Promise(async function(res,rej){
    try{
      var pkce=await genPkce();
      var state=genState();
      var tid=self._cfg.auth.authority.replace(/.*\//,'');
      var redir=self._cfg.auth.redirectUri||location.origin+location.pathname;
      var scopes=((req&&req.scopes)||[]).concat(['offline_access']).join(' ');
      var url='https://login.microsoftonline.com/'+tid+'/oauth2/v2.0/authorize'
        +'?client_id='+encodeURIComponent(self._cfg.auth.clientId)
        +'&response_type=code'
        +'&redirect_uri='+encodeURIComponent(redir)
        +'&scope='+encodeURIComponent(scopes)
        +'&state='+state
        +'&code_challenge='+pkce.challenge
        +'&code_challenge_method=S256'
        +'&prompt=select_account';

      var w=800,h=600,l=(screen.width-w)/2,t=(screen.height-h)/2;
      var pop=window.open(url,'_msal_popup',
        'width='+w+',height='+h+',left='+l+',top='+t+',toolbar=0,menubar=0,location=0');
      if(!pop){rej(new Error('Popup bloqueado. Permita popups para este site e tente novamente.'));return;}

      var timer=setInterval(async function(){
        if(!pop||pop.closed){
          clearInterval(timer);
          rej(new Error('Login cancelado.'));
          return;
        }
        var href='';
        try{href=pop.location.href;}catch(e){return;}
        var base=redir.split('?')[0];
        if(href&&(href.startsWith(base)||href.startsWith(location.origin+location.pathname))){
          pop.close();
          clearInterval(timer);
          var params=new URL(href).searchParams;
          var code=params.get('code');
          if(!code){rej(new Error('Sem código de autorização.'));return;}
          if(params.get('state')!==state){rej(new Error('State inválido.'));return;}
          // Trocar code por tokens
          try{
            var body=new URLSearchParams({
              client_id:self._cfg.auth.clientId,
              grant_type:'authorization_code',
              code:code,
              redirect_uri:redir,
              code_verifier:pkce.verifier,
              scope:scopes
            });
            var r=await fetch('https://login.microsoftonline.com/'+tid+'/oauth2/v2.0/token',
              {method:'POST',body:body,headers:{'Content-Type':'application/x-www-form-urlencoded'}});
            var tk=await r.json();
            if(tk.error){rej(new Error(tk.error_description||tk.error));return;}
            var claims=parseJwt(tk.id_token||tk.access_token);
            var acc={
              homeAccountId:claims.oid||claims.sub||'',
              username:claims.upn||claims.preferred_username||claims.email||'usuario',
              name:claims.name||'Usuário Bocchi'
            };
            self._save({
              access_token:tk.access_token,
              refresh_token:tk.refresh_token||null,
              expires_at:Date.now()+tk.expires_in*1000,
              account:acc,
              scopes:scopes.split(' ')
            });
            res({accessToken:tk.access_token,account:acc,idToken:tk.id_token});
          }catch(e){rej(e);}
        }
      },250);
    }catch(e){rej(e);}
  });
};

// Expor globalmente como "msal"
var mod={PublicClientApplication:PCA};
if(typeof module!=='undefined'&&module.exports)module.exports=mod;
else g.msal=mod;

})(typeof globalThis!=='undefined'?globalThis:typeof window!=='undefined'?window:this);
